        ]
        Ranks = [
            (3, 3),
            (2, 3, 4),
            (2, 3, 4, 5),
            (2, 3, 4, 5, 6)
        ]
        Dims = [
            (10, 9), 
            (10, 9, 8),
            (10, 9, 8, 7),
            (10, 9, 8, 7, 6),
        ]

        for i in eachindex(Dims) # test for order 2, …, 5
            ranks = Ranks[i]
            dims = Dims[i]
            M = Tucker(dims, ranks)

            p1 = allocate(P1[i])
            copyto!(p1, P1[i])
            p2 = allocate(P2[i])
            copyto!(p2, P2[i])
            X = copy(tangent_vectors[i])

            Y_manual = allocate(X)
            Y = allocate(X)

            Y_manual = project!(M, Y_manual, p2, embed(M, p1, X))
            Y = vector_transport_to!(M, Y, p1, X, p2, ProjectionTransport())
            @test isapprox(M, p2, Y_manual, Y, atol=atol, rtol=rtol)
            @test isapprox(embed(M, p2, Y_manual), embed(M, p2, Y), atol=atol, rtol=rtol)

            # test transport for in-place update
            p1 = allocate(P1[i])
            copyto!(p1, P1[i])
            p2 = allocate(P2[i])
            copyto!(p2, P2[i])
            X = copy(tangent_vectors[i])

            Y_manual = allocate(X)
            Y_manual = project!(M, Y_manual, p2, embed(M, p1, X))

            vector_transport_to!(M, X, p1, X, p2, ProjectionTransport())
            @test isapprox(M, p2, Y_manual, X, atol=atol, rtol=rtol)
            @test isapprox(embed(M, p2, Y_manual), embed(M, p2, X), atol=atol, rtol=rtol)
        end
    end

    @testset "product of Tucker manifolds" begin
        M = ProductManifold(
            Tucker((18, 16, 14), (4, 3, 3)),
            Tucker((18, 16, 14), (4, 3, 3)),
        )
        p0 = rand(M)
        X = rand(M; vector_at = p0)
        Y = copy(M, X)
        Y .*= 2
        @test isapprox(M, p0, X + X, Y)
    end
end
